//SPDX-License-Identifier:MIT

pragma solidity ^0.8.7;

import "./MIMCSpoge.sol";

interface INftMarketPlace {
    function withdrawProceeds(uint256 com) external;
}

interface IVerifier {
    function verifyProof(uint[2] memory a, uint[2][2] memory b, uint[2] memory c, uint[3] memory input) external returns(bool);
}

contract ZkContract{

    uint256[10] levelDefaults = [
        23183772226880328093887215408966704399401918833188238128725944610428185466379,
        24000819369602093814416139508614852491908395579435466932859056804037806454973,
        90767735163385213280029221395007952082767922246267858237072012090673396196740,
        36838446922933702266161394000006956756061899673576454513992013853093276527813,
        68942419351509126448570740374747181965696714458775214939345221885282113404505,
        50082386515045053504076326033442809551011315580267173564563197889162423619623,
        73182421758286469310850848737411980736456210038565066977682644585724928397862,
        60176431197461170637692882955627917456800648458772472331451918908568455016445,
        105740430515862457360623134126179561153993738774115400861400649215360807197726,
        76840483767501885884368002925517179365815019383466879774586151314479309584255
    ];

    event Mint(uint256 root, uint256[10] hashPairings, uint8[10] pairDirection);
    event Check(address to, uint256 nullifierHash);

    address verifier;
    Hasher hasher;

    uint8 public treeLevel = 10;
    uint256 public nextLeafIdx = 0;

    mapping(uint256=>bool) public roots;
    mapping(uint8=>uint256) lastLevelHash;
    mapping(uint256=>bool) private nullExists;
    mapping(uint256=>bool) private comExists;

    constructor(
        address _hasher,
        address _verifier
    ){
        hasher = Hasher(_hasher);
        verifier = _verifier;
    }

    function minting(uint256 _commitment) external {
        require(!comExists[_commitment],"Duplicate commitment hash.");
        require(nextLeafIdx < 2 **treeLevel, "Tree full");

        uint256 newRoot;
        uint256[10] memory hashPairings;
        uint8[10] memory hashDirections;

        uint256 currentIdx = nextLeafIdx;
        uint256 currentHash = _commitment;

        uint256 left;
        uint256 right;
        uint256[2] memory ins;


        for(uint8 i = 0; i < treeLevel; i++){

            if(currentIdx % 2 == 0){
                left = currentHash;
                right = levelDefaults[i];
                hashPairings[i] = levelDefaults[i];
                hashDirections[i] = 0;
            }else{
                left = lastLevelHash[i];
                right = currentHash;
                hashPairings[i] = lastLevelHash[i];
                hashDirections[i] = 1;
            }
            lastLevelHash[i] = currentHash;

            ins[0] = left;
            ins[1] = right;

            (uint256 h) = hasher.MiMC5Sponge{ gas: 150000 }(ins, _commitment);

            currentHash = h;
            currentIdx = currentIdx / 2;
        }

        newRoot = currentHash;
        roots[newRoot] = true;
        nextLeafIdx += 1;

        comExists[_commitment] = true;
        emit Mint(newRoot, hashPairings, hashDirections);
    }

    function withdraw(
        uint[2] memory a,
        uint[2][2] memory b,
        uint[2] memory c,
        uint[2] memory input,
        address nftMPAddress,
        uint256 com
    ) external {
        uint256 _root = input[0];
        uint256 _nullifierHash = input[1];

        require(nullExists[_nullifierHash],"NullifierHash soes not exits");
        require(roots[_root], "not-root");

        uint256 _addr = uint256(uint160(msg.sender));
        (bool verifyOK, ) = verifier.call(abi.encodeCall(IVerifier.verifyProof, (a, b, c, [_root, _nullifierHash, _addr])));
        require(verifyOK, "invalid-proof");

        INftMarketPlace(nftMPAddress).withdrawProceeds(com);
    } 

    function null_exists(uint256 i) view public returns(bool){
        return nullExists[i];
    }

    function registerNull(uint256 i) public {
        nullExists[i] = true;
    }

    function com_exists(uint256 i) view public returns(bool){
        return comExists[i];
    }

    function regiterCom(uint256 i) public {
        comExists[i] = true;
    }
}

contracts/zkNFT.sol.content:
// SPDX-License-Identifier:MIT
pragma solidity ^0.8.7;

interface IZkNFT {

    function approve(uint256 _tokenID, address op) external;
    function getApprovedAdd(uint256 _tokenID) external view returns(address);    
    function ownerOf(uint256 _tokenID) external view returns (uint256);
    function transferNFT(uint256 _tokenID, uint256 nullifierHash, address buyer) external;
    function transferFrom(uint256 ownerNul, uint256 buyerNul, address buyer, uint256 _tokenID) external;
}

contract zkNFT is IZkNFT{

    event NFTTransfered(uint256 indexed from ,uint256 indexed to ,uint256 indexed tokenID);
    event MetadataUpdate(uint256 indexed tokenID);

    struct proof{
        uint[2] a;
        uint[2][2] b;
        uint[2] c;
        uint[2] input;
    }

    mapping(address => mapping (uint256=> uint256)) private addToCom;
    mapping(uint256 => address) private comToAdd;
    mapping(address => uint256) private noOfComs; 
    mapping(uint256 => uint256) private owners;
    mapping(uint256 => string) private tokenURIs;
    mapping (uint256 => address) tokenIDToAdd;
    mapping (uint256 => proof) private mapProof;

    string _name = "zkMP";
    string _symbol = "Z";
    uint256 private tokenID;

    constructor(){
        tokenID = 0;
    }

    function createNFT(uint256 commitment, string memory tokenURI) public {
        address creator = msg.sender;

        setAddAndCom(creator,commitment);
        mintNFT(commitment,tokenURI);
        tokenID++;
    }

    function mintNFT(uint256 commitment,string memory _tokenURI) internal {
        owners[tokenID] = commitment;
        setTokenURI(tokenID,_tokenURI);

        emit NFTTransfered(0, commitment, tokenID);
    }

    function setTokenURI(uint256 tokenId, string memory _tokenURI) internal {
        tokenURIs[tokenId] = _tokenURI;

        emit MetadataUpdate(tokenId);
    }

    function transferFrom(uint256 ownerCom, uint256 buyerCom, address buyer, uint256 _tokenID) public override{

        require(getApprovedAdd(_tokenID) == msg.sender, "No approved to make this call");
        require(keccak256(abi.encodePacked(ownerOf(_tokenID))) == keccak256(abi.encodePacked(ownerCom)), "Invalid comifier hash");

        transferNFT(_tokenID, buyerCom, buyer);
    }

    function transferNFT(uint256 _tokenID, uint256 commitment, address buyer) public override{
        // owner losing nft
        uint256 crtrCom = owners[_tokenID];
        address owner = comToAdd[crtrCom]; 
        delete owners[_tokenID];
        uint256 n = noOfComs[owner] - 1;
        delete addToCom[owner][n];
        noOfComs[owner] -= 1 ;

        // Buyer getting nft
        setAddAndCom(buyer,commitment);
        owners[_tokenID] = commitment; 
    }   

    function setProof(uint256 commitment,proof memory pr) public {
        mapProof[commitment] = pr;
    }

    function getProof(uint256 commitment) view public returns(proof memory){
        return mapProof[commitment];
    }

    function ownerOf(uint256 _tokenID) public override view returns (uint256){
        return owners[_tokenID];
    }

    function exists(uint256 _tokenID) internal view returns (bool) {
       return !(owners[_tokenID] == 0);
    }

    function setAddAndCom(address add, uint256 com) internal{
        comToAdd[com] = add;
        uint256 n = noOfComs[add];
        addToCom[add][n] = com;
        noOfComs[add] += 1;
    }


    function approve(uint256 _tokenID, address op) public override{
        uint256 ownerCom = owners[_tokenID];
        address owner = comToAdd[ownerCom];

        require(op != owner,"Invalid operator address");
        tokenIDToAdd[_tokenID] = op;
    }

    function getApprovedAdd(uint256 _tokenID) public override view returns(address){
        return tokenIDToAdd[_tokenID];
    }

    function getNumberOfTokens() public view returns(uint256) {
        return tokenID;
    }

    function name() public view returns (string memory) {
        return _name;
    }

    function symbol() public view returns (string memory) {
        return _symbol;
    }
}

